    public string WarehouseName { get; set; } = "Warehouse A";

    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A"),
        ("WH-002", "Warehouse B"),
        ("WH-003", "Warehouse C"),
    ];
}

namespace sv_de0ed069cda648d7bf8a8880ec3c87f0.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts for a warehouse.
/// Components subscribe to <see cref="OnChange"/> and call
/// <see cref="RefreshAsync"/> to trigger a simulated database check.
/// Scoped lifetime ensures each user circuit gets its own instance.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int LowStockCount { get; private set; }

    public event Action? OnChange;

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database query â€” return a random count between 0 and 15.
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Fetches a new count for <paramref name="warehouseId"/> and notifies
    /// every subscribed component so they all re-render with the latest value.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        LowStockCount = await GetLowStockCountAsync(warehouseId);
        OnChange?.Invoke();
    }
}

