@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@using sv_de0ed069cda648d7bf8a8880ec3c87f0.Services
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="mb-3">
    <strong>Current warehouse:</strong> @(Warehouse?.WarehouseName ?? "â€”")
    <span class="text-muted">(@(Warehouse?.WarehouseId ?? ""))</span>
</div>

<div class="card mb-4" style="max-width: 320px;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="display-4">
            @AlertService.LowStockCount
        </p>
        <p class="text-muted">items below minimum level</p>
        <p class="text-muted small">Refreshes every 10 seconds while this page is open.</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseState? Warehouse { get; set; }

    private CancellationTokenSource? _cts;
    private Action? _handler;

    protected override async Task OnInitializedAsync()
    {
        // Subscribe so this component re-renders when alert data changes.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;

        // Fetch initial data immediately.
        if (Warehouse is not null)
        {
            await AlertService.RefreshAsync(Warehouse.WarehouseId);
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            StartPolling();
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Warehouse changed via cascading parameter â€” restart polling for new warehouse.
        if (Warehouse is not null)
        {
            StopPolling();
            await AlertService.RefreshAsync(Warehouse.WarehouseId);
            StartPolling();
        }
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                if (Warehouse is not null)
                {
                    await AlertService.RefreshAsync(Warehouse.WarehouseId);
                }
            }
        }
        catch (OperationCanceledException) { }
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        StopPolling();
        AlertService.OnChange -= _handler;
    }
}

